insert into books (id, title, author, synopsis, buy_link, cover_bg, cover_text, tags, created_at) values
  ('11111111-1111-1111-1111-000000000001',
   'Until the Storm',
   'Mira Ashwood',
   $$When a sudden blizzard traps rival journalists Eden Pierce and Holt Ravensdale in a remote Vermont cabin, two people who have spent three years sharpening their pens against each other discover that warmth has a price neither expected to pay.$$,
   'https://ggvert99.github.io/inkblotV2/',
   'linear-gradient(135deg, #2c3e50 0%, #e74c3c 100%)',
   '#FFF8F0',
   ARRAY['enemies-to-lovers','forced-proximity','slow-burn'],
   '2025-01-15T10:00:00Z'),
  ('11111111-1111-1111-1111-000000000002',
   'Paper Walls',
   'Lena Cross',
   $$Best friends since college, Margot and Theo share a Brooklyn walk-up with walls so thin they have heard every heartbreak. When Margot's latest relationship ends at 2 a.m., the wall between them stops being a barrier and starts being a question.$$,
   'https://ggvert99.github.io/inkblotV2/',
   'linear-gradient(135deg, #f093fb 0%, #f5576c 100%)',
   '#FFFFFF',
   ARRAY['slow-burn','friends-to-lovers'],
   '2025-01-20T10:00:00Z'),
  ('11111111-1111-1111-1111-000000000003',
   'The Second Cup',
   'Ada Monroe',
   $$Eight years after she left Cedar Hollow without a goodbye, Wren Calloway walks back into the only coffee shop in town and finds Sawyer Beckett behind the counter she once called home. Some apologies cannot be poured. Some can.$$,
   'https://ggvert99.github.io/inkblotV2/',
   'linear-gradient(135deg, #4facfe 0%, #00f2fe 100%)',
   '#0a2540',
   ARRAY['second-chance','small-town'],
   '2025-01-25T10:00:00Z'),
  ('11111111-1111-1111-1111-000000000004',
   'Rule Number Five',
   'J.T. Wilder',
   $$Junior partner Imogen Vale needs a date for the firm's gala. Her cynical office-mate Daniel Cho needs leverage with HR. Five rules, one weekend, zero feelings. Rule number five was the one neither of them should have agreed to.$$,
   'https://ggvert99.github.io/inkblotV2/',
   'linear-gradient(135deg, #43e97b 0%, #38f9d7 100%)',
   '#0a2018',
   ARRAY['fake-dating','workplace-romance'],
   '2025-02-01T10:00:00Z'),
  ('11111111-1111-1111-1111-000000000005',
   'Midnight Margin',
   'Clara Voss',
   $$Marlow Quinn does not need cheerful, especially not at her dying secondhand bookshop on Quill Street. Then a sunshine-smiling philosophy graduate named Jude shows up with a resume, a thermos, and an inability to read the room.$$,
   'https://ggvert99.github.io/inkblotV2/',
   'linear-gradient(135deg, #fa709a 0%, #fee140 100%)',
   '#2a1010',
   ARRAY['grumpy-sunshine','opposites-attract'],
   '2025-02-08T10:00:00Z'),
  ('11111111-1111-1111-1111-000000000006',
   'One Room Left',
   'Nora Bellamy',
   $$A botched conference booking. A snowed-in coastal inn. One bed, two coworkers, and a secret that could end both their careers if anyone in the building below them suspects what is happening upstairs.$$,
   'https://ggvert99.github.io/inkblotV2/',
   'linear-gradient(135deg, #a18cd1 0%, #fbc2eb 100%)',
   '#1a0d2e',
   ARRAY['one-bed','forbidden-love','forced-proximity'],
   '2025-02-14T10:00:00Z')
